  type = type === undefined ? 0 : type;
  fv = fv === undefined ? 0 : fv;

  rate = parseNumber(rate);
  pmt = parseNumber(pmt);
  pv = parseNumber(pv);
  fv = parseNumber(fv);
  type = parseNumber(type);

  if (anyIsError(rate, pmt, pv, fv, type)) {
    return value
  }

  if (rate === 0) {
    return -(pv + fv) / pmt
